import React from "react";
import { Link } from "react-router-dom";

function Navbar() {
  return (
    <header className="navbar">
      <div className="container navbar-content">
        <div className="brand-logo">
          <div className="brand-icon">
            <span className="brand-icon-letter">C</span>
          </div>

          <div className="brand-text">
            <div className="brand-name">Culinary Book</div>
            <div className="brand-subtitle">Przepisy • Smaki • Inspiracje</div>
          </div>
        </div>

        <nav className="nav-links">
          <Link to="/">Strona główna</Link>
          <Link to="/przepisy">Przepisy</Link>
          <Link to="/logowanie">Logowanie</Link>
          <a href="/" className="register-button">Zarejestruj się</a>
        </nav>
      </div>
    </header>
  );
}

export default Navbar;
